var RTR_KEY='rtr_unlocked_v1';
function rtrUnlocked(){ try{ if(sessionStorage.getItem(RTR_KEY)==='1') return true; }catch(e){} return window.__rtrUnlocked===true; }
window.rtrUnlocked=rtrUnlocked;
window.rtrUnlock=function(){ try{ sessionStorage.setItem(RTR_KEY,'1'); }catch(e){} window.__rtrUnlocked=true; };
var RTR_GATED={marketplace:1,'command-center':1,'deployment-view':1};
function rtRoute(){
  var map={home:'v-home',marketplace:'v-marketplace','command-center':'v-cc','deployment-view':'v-dv','sign-in':'v-signin'};
  var h=(location.hash||'').replace('#','');
  if(!map[h]){
    // not a view route -> treat as an in-page anchor inside the homepage (e.g. #research-analytics from a dept card)
    var anchor=h?document.getElementById(h):null;
    var home=document.getElementById('v-home');
    if(anchor && home && home.contains(anchor)){
      if(home.classList.contains('active')) return;   // already on home: let the native anchor scroll run, don't reset to top
      for(var k in map){ var el=document.getElementById(map[k]); if(el) el.classList.toggle('active', k==='home'); }
      document.querySelectorAll('.nav-set [data-view]').forEach(function(a){ a.classList.toggle('active', a.getAttribute('data-view')==='home'); });
      window.dispatchEvent(new Event('resize'));
      anchor.scrollIntoView({block:'start'});
      return;
    }
    h='home';
  }
  if(RTR_GATED[h] && !rtrUnlocked()){
    if(((location.hash||'').replace('#',''))!=='sign-in'){ location.hash='sign-in'; return; }
    h='sign-in';
  }
  for(var k in map){ var el=document.getElementById(map[k]); if(el) el.classList.toggle('active', k===h); }
  document.querySelectorAll('.nav-set [data-view]').forEach(function(a){
    a.classList.toggle('active', a.getAttribute('data-view')===h); });
  window.scrollTo(0,0);
  window.dispatchEvent(new Event('resize'));   // let the now-visible view re-fit its layout
  if(h==='command-center' && window.rtrAxMaybe){ window.rtrAxMaybe(); }
}
window.addEventListener('hashchange', rtRoute);

