function ccCard(a,opt){
  opt=opt||{};
  const acc=ACC[a.dept],tint=TINT[a.dept];
  const notif=a.notif>0?`<span class="nb">${a.notif}</span>`:'';
  const pinHtml=opt.noPin?'':`<button class="pin ${a.pinned?'on':''}" data-pin="1">${a.pinned?PINF:PIN}</button>`;
  const ribbon=a.rec?`<span class="ribbon">Recommended</span>`:'';
  let foot='';
  if(opt.deploy) foot=`<div class="cc-foot"><span>${a.status==='active'?'Deployed':'Tap to deploy'}</span><label class="sw"><input type="checkbox" ${a.status==='active'?'checked':''}><span></span></label></div>`;
  let stClass='off', stLabel='On deck';
  if(a.status==='active'){stClass='on';stLabel='Active';}
  else if(opt.forHire){stClass='hire';stLabel='For hire';}
  const addBtn = opt.add ? `<button class="add-btn" data-add="1">+ Add</button>` : '';
  const goBtn = opt.goto ? `<button class="cc-go" data-go="1" title="Go to ${a.name}">${GO}</button>` : '';
  return `<article class="cc-card ${(a.status==='active'||opt.add)?'':'dim'}${a.rec?' rec':''}" data-agent="${(a.name||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;')}" data-dept="${a.dept}" style="--accent:${acc};--tint:${tint}">
    ${ribbon}
    <div class="cc-top">
      <div class="cc-avi"><img src="${AV[a.av]}" alt=""></div>
      <div class="cc-tt"><div class="cc-name">${a.name}</div><div class="cc-tag">${DNAME[a.dept]}</div></div>
      <div class="cc-actions">${notif}${pinHtml}</div>
    </div>
    <div class="cc-meta"><span class="st ${stClass}"><i></i>${stLabel}</span><span class="act">${a.activity||''}</span>${goBtn}</div>
    ${foot}${addBtn}
  </article>`;
}
function mcCard(a){
  const acc=ACC[a.dept],tint=TINT[a.dept];
  const caps=a.bullets.map(b=>`<li>${b}</li>`).join('');
  return `<article class="mc-card" style="--accent:${acc};--tint:${tint}">
    <div class="mc-top">
      <div class="mc-avi"><img src="${AV[a.av]}" alt=""></div>
      <div><div class="mc-name">${a.name}</div><div class="mc-tag">${DNAME[a.dept]}</div></div>
    </div>
    <ul class="mc-caps">${caps}</ul>
    <div class="mc-solves">
      <div class="mc-sv-text"><span class="mc-sl">Solves for</span><span class="mc-sv">${a.solves}</span></div>
      <button class="mc-add" data-add="1"><span class="plus">+</span> Add</button>
    </div>
  </article>`;
}
function uiItem(u){
  return `<div class="ui${u.read?' read':''}" data-dept="${u.dept}" style="--accent:${ACC[u.dept]};--tint:${TINT[u.dept]}"><div class="ui-avi"><img src="${AV[u.av]}"></div>
    <div class="ui-mid"><div class="ui-name">${u.name}</div><div class="ui-txt">${u.txt}</div><div class="ui-time">${u.time}</div></div>
    <div class="ui-acts"><div class="ui-acts-top"><button class="ui-act flag" data-flag="1" title="Flag">${FLAG}</button><button class="ui-act del" data-del="1" title="Delete">${TRASH}</button></div><button class="cc-go" data-go="1" title="Go to ${u.name}">${GO}</button></div>
    <div class="ui-status"><span class="dot"></span><span class="rd">Read</span></div></div>`;
}

