function aView(a){ return Object.assign({},a,{status:a.deployed?'active':'ondeck',activity:a.deployed?a.actLive:a.actDeck}); }
function odMeta(){ return '<span class="st off"><i></i>'+AGENTS.filter(a=>!a.deployed).length+' on deck</span>'; }
function dpMeta(){ return '<span class="st on"><i></i>'+AGENTS.filter(a=>a.deployed).length+' active</span>'; }
function odBody(){ const list=AGENTS.filter(a=>!a.deployed);
  const cards=list.length?list.map(a=>ccCard(aView(a),{deploy:true})).join(''):'<div class="panel-empty"><span>All your agents are deployed.</span></div>';
  return filterBar(list)+scrollWrap('<div class="stack">'+cards+'</div>','od'); }
function pnBody(){ const list=AGENTS.filter(a=>a.pinned);
  const cards=list.length?list.map(a=>ccCard(aView(a),{goto:true})).join(''):'<div class="panel-empty"><span>Pin an agent to keep it close at hand.</span></div>';
  return '<div class="cc-grid">'+cards+'</div>'; }
function dpBody(){ const list=AGENTS.filter(a=>a.deployed);
  const sw='<button class="deploy-switch" id="switchView"><span class="ds-rank">'+RANK3+'</span><span class="ds-tx"><b>Switch to Deployment View</b></span><span class="ds-arrow">'+GO+'</span></button>';
  const body=list.length?dirGroup():'<div class="panel-empty"><span>No agents deployed yet. Flip a Tap-to-deploy toggle to activate one.</span></div>';
  return sw+filterBar(list)+scrollWrap(body,'dp'); }
function dirGroup(){
  const g={}; AGENTS.filter(a=>a.deployed).forEach(a=>{(g[a.dept]=g[a.dept]||[]).push(a);});
  const order=DEPT_ORDER.filter(d=>g[d]&&g[d].length);
  return `<div class="dir-stack">${order.map(dept=>{
    const acc=ACC[dept],tint=TINT[dept],list=g[dept];
    const sum=DEPT_SUM[dept]||(list.length+" "+DNAME[dept]+" agents are live and reporting in.");
    const head = list.length>1 ? `<div class="dir-head"><div class="dir-avi"><img src="${DIRAV[dept]}"></div>
      <div class="dir-body"><div class="dir-name">${DNAME[dept]} Director (R2R)</div><div class="dir-sum">${sum}</div></div></div>` : '';
    return `<div class="director" data-dept="${dept}" style="--accent:${acc};--tint:${tint}">
      ${head}<div class="dir-agents">${list.map(a=>ccCard(aView(a),{deploy:true,goto:true})).join('')}</div></div>`;
  }).join('')}</div>`;
}

