    document.querySelectorAll('.g-od .scroll-cue, .g-dp .scroll-cue').forEach(c=> c.onclick=(e)=>{ e.stopPropagation(); const sc=document.querySelector('.pscroll[data-scroll="'+c.dataset.cue+'"]'); if(sc) sc.scrollBy({top:170,behavior:'smooth'}); });
